```llvm
define i32 @test(i1 %cond, i32 %x, i32 %y) {
entry:
  %cond.ext = zext i1 %cond to i32
  %shl = shl i32 %cond.ext, %y
  %and = and i32 %x, %shl
  ret i32 %and
