  ret i1 %cmp
}
```
### Optimized IR
```llvm
target datalayout = "p:32:32"

define i1 @test_inttoptr_cmp(i64 %x, i64 %y) {
  %cmp = icmp eq i64 %x, %y
  ret i1 %cmp
